class Solution:
    def longestCommonSubsequence(self, text1: str, text2: str) -> int:
        m, n = len(text1), len(text2)
        if m < n:
            text1, text2 = text2, text1
            m, n = n, m
        prev = [0]*(n+1)
        for c1 in text1:
            curr = [0]*(n+1)
            for j, c2 in enumerate(text2, 1):
                if c1 == c2:
                    curr[j] = prev[j-1] + 1
                else:
                    curr[j] = max(prev[j], curr[j-1])
            prev = curr
        return prev[-1]
